#include <generator>
#include <ranges>
#include <print>

std::generator<long long> fibonacci() {
    long long a = 0, b = 1;
    while (true) {
        co_yield a;
        a = std::exchange(b, a + b);
    }
}

int main() {
    for (long long n : fibonacci() | std::views::take(10))
        std::println("{}", n);
}

#include <generator>
#include <ranges>
#include <vector>
#include <print>

std::generator<int> range(int from, int to) {
    for (int i = from; i < to; ++i)
        co_yield i;
}

std::generator<int> concat(std::vector<std::pair<int,int>> ranges_spec) {
    for (auto [from, to] : ranges_spec)
        co_yield std::ranges::elements_of(range(from, to));
}

int main() {
    // Compose generator with views
    auto squares = range(1, 6)
        | std::views::transform([](int x){ return x * x; });

    std::print("Squares 1-5: ");
    for (int s : squares) std::print("{} ", s);
    std::println("");

    // Nested generators via elements_of
    std::vector<std::pair<int,int>> spec = {{1,4}, {10,13}};
    std::print("Concat: ");
    for (int x : concat(spec)) std::print("{} ", x);
    std::println("");
}

#include <generator>
#include <print>
#include <string>

std::generator<std::string> execution_trace() {
    std::println("[coroutine] started");
    co_yield "first value";

    std::println("[coroutine] resumed after first yield");
    co_yield "second value";

    std::println("[coroutine] resumed after second yield");
    co_yield "third value";

    std::println("[coroutine] reached end — returning");
    // co_return; is implicit here
}

int main() {
    std::println("[main] creating generator");
    auto gen = execution_trace();

    std::println("[main] starting iteration");
    for (const auto& val : gen) {
        std::println("[main] got: {}", val);
    }
    std::println("[main] iteration complete");
}

#include <generator>
#include <ranges>
#include <vector>
#include <print>

struct Node {
    int value;
    std::vector<Node> children;
};

std::generator<int> dfs(const Node& n) {
    co_yield n.value;
    for (const auto& child : n.children)
        co_yield std::ranges::elements_of(dfs(child));
}

int main() {
    Node root = {1, {
        {2, {{4, {}}, {5, {}}}},
        {3, {{6, {}}}}
    }};

    std::print("DFS order: ");
    for (int v : dfs(root))
        std::print("{} ", v);
    std::println("");
}

#include <generator>
#include <ranges>
#include <vector>
#include <algorithm>
#include <print>

std::generator<int&> mutable_view(std::vector<int>& v) {
    for (int& x : v)
        co_yield x;
}

std::generator<long long> powers_of_2() {
    long long p = 1;
    while (true) {
        co_yield p;
        p *= 2;
    }
}

int main() {
    // Mutable reference: double each element
    std::vector<int> data = {1, 2, 3, 4, 5};
    for (int& x : mutable_view(data))
        x *= 2;

    std::print("After doubling: ");
    for (int x : data) std::print("{} ", x);
    std::println("");

    // Infinite generator + views: first 8 powers of 2
    std::print("Powers of 2: ");
    for (long long p : powers_of_2() | std::views::take(8))
        std::print("{} ", p);
    std::println("");

    // std::ranges::find_if on a generator
    auto gen = powers_of_2();
    auto it = std::ranges::find_if(gen, [](long long x){ return x > 100; });
    std::println("First power of 2 > 100: {}", *it);
}
